 253→router.get('/getNotifications', requireAuth, async(req, res) =>{
 254→    const {before, limit} = req.query;
 255→    const userId = req.userId;
 256→
 257→    // Fetch a generous amount from both tables, then merge and paginate
 258→    const fetchLimit = parseInt(limit) + 1;
 259→
 260→    let journalQuery = supabase
 261→    .from('notifications')
 262→    .select(
 263→        `*,
 264→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 265→        users!sender_id(name, user_email, image_url, id, badge),
 266→        constellation_id,
 267→        constellations!constellation_id(status, star_id_a, star_id_b)
 268→        `
 269→    )
 270→    .eq('receiver_id', userId)
 271→    .order('created_at', {ascending: false})
 272→    .order('id', {ascending: false})
 273→    .limit(fetchLimit)
 274→
 275→    let opinionQuery = supabase
 276→    .from('notification_opinions')
 277→    .select(
 278→        `*,
 279→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 280→        users!sender_id(name, user_email, image_url, id, badge)
 281→        `
 282→    )
 283→    .eq('receiver_id', userId)
 284→    .order('created_at', {ascending: false})
 285→    .order('id', {ascending: false})
 286→    .limit(fetchLimit)
 287→
 288→    if(before){
 289→        journalQuery = journalQuery.lt('created_at', before);
 290→        opinionQuery = opinionQuery.lt('created_at', before);
 291→    }
 292→
 293→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 294→
 295→    if(journalResult.error){
 296→        console.error('error while fetching data from notification table:', journalResult.error);
 297→        return res.status(500).json({error: 'error fetching data from notification table'});
 298→    }
 299→    if(opinionResult.error){
 300→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 301→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 302→    }
 303→
 304→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 305→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 306→
 307→    // Merge and sort by created_at descending
 308→    const merged = [...journalNotifs, ...opinionNotifs]
 309→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 310→
 311→    // Likes/bookmarks lookup only for journal notifications
 312→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 313→
 314→    let hasLikedResult = [];
 315→    let hasBookMarkedResult = [];
 316→    if(journalIds.length > 0){
 317→        const [hasLiked, hasBookMarked] = await Promise.all([
 318→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 319→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 320→        ]);
 321→
 322→        if(hasLiked.error || hasBookMarked.error){
 323→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 324→        }
 325→        hasLikedResult = hasLiked.data || [];
 326→        hasBookMarkedResult = hasBookMarked.data || [];
 327→    }
 328→
 329→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 330→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 331→
 332→    const formatted = merged.map((notif) => ({
 333→        ...notif,
 334→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 335→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 336→    }))
 337→
 338→    const hasMore = formatted.length > parseInt(limit);
 339→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 340→
 341→    return res.status(200).json(
 342→        {
 343→            hasMore: hasMore,
 344→            data: slicedData,
 345→        }
 346→    )
 347→
 348→})
