  5→const updateInfiniteJournalsCache = (old, updater) => {
  6→    if (!old || !Array.isArray(old.pages)) return old;
  7→
  8→    return {
  9→        ...old,
 10→        pages: old.pages.map((page) => ({
 11→            ...page,
 12→            data: Array.isArray(page?.data) ? page.data.map(updater) : page?.data,
 13→        })),
 14→    };
 15→};
 16→
 17→const normalizeInteractionFlag = (value) => {
 18→    if(typeof value === 'boolean') return value;
 19→    if(typeof value === 'string'){
 20→        const normalized = value.trim().toLowerCase();
 21→        if(normalized === 'true') return true;
 22→        if(normalized === 'false') return false;
 23→    }
 24→    if(typeof value === 'number'){
 25→        return value === 1;
 26→    }
 27→    return Boolean(value);
 28→};
 29→
 30→const normalizeCount = (value) => {
 31→    const number = Number(value);
 32→    if(!Number.isFinite(number) || number < 0){
 33→        return 0;
 34→    }
 35→    return number;
 36→};
 37→
 38→const getNextToggleCount = (isActive, currentCount) => {
 39→    return isActive
 40→        ? Math.max(0, currentCount - 1)
 41→        : currentCount + 1;
 42→};
 43→
 44→const toJournalKey = (journalId) => {
 45→    if(journalId === undefined || journalId === null){
 46→        return '';
 47→    }
 48→    return String(journalId);
 49→};
