 51→export const useBookMarkMutation = (session, userId) => {
 52→    const queryClient = useQueryClient();
 53→    const inFlightBookmarkIdsRef = useRef(new Set());
 54→
 55→    const mutation = useMutation({
 56→        mutationFn: (data) => addBookmark(session?.access_token, data),
 57→
 58→        onMutate: async(data) =>{
 59→            queryClient.cancelQueries({ queryKey: ['journals'] });
 60→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
 61→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
 62→
 63→            const previousData = [
 64→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
 65→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
 66→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
 67→            ];
 68→
 69→            const updater = (journal) => {
 70→                if(journal.id !== data.journalId) return journal;
 71→
 72→                const isBookmarked = normalizeInteractionFlag(journal?.has_bookmarked);
 73→                const count = normalizeCount(journal?.bookmark_count?.[0]?.count);
 74→                const nextCount = getNextToggleCount(isBookmarked, count);
 75→
 76→                return{
 77→                    ...journal,
 78→                    has_bookmarked: !isBookmarked,
 79→                    bookmark_count: [{count: nextCount}]
 80→                };
 81→            };
 82→
 83→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 84→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 85→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
 86→
 87→            return {previousData};
 88→        },
 89→        onError: (err,data, context) =>{
 90→            context?.previousData?.forEach(([key, value]) => {
 91→                queryClient.setQueryData(key, value);
 92→            });
 93→        },
 94→        onSettled: () =>{
 95→            queryClient.invalidateQueries({ queryKey: ['journals'] });
 96→            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
 97→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
 98→        }
 99→    });
100→
101→    const guardedMutate = (variables, options) => {
102→        const journalKey = toJournalKey(variables?.journalId);
103→        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
104→            return;
105→        }
106→
107→        if(journalKey){
108→            inFlightBookmarkIdsRef.current.add(journalKey);
109→        }
110→
111→        mutation.mutate(variables, {
112→            ...options,
113→            onSettled: (data, error, vars, context) => {
114→                if(journalKey){
115→                    inFlightBookmarkIdsRef.current.delete(journalKey);
116→                }
117→                options?.onSettled?.(data, error, vars, context);
118→            }
119→        });
120→    };
121→
122→    const guardedMutateAsync = async (variables, options) => {
123→        const journalKey = toJournalKey(variables?.journalId);
124→        if(journalKey && inFlightBookmarkIdsRef.current.has(journalKey)){
125→            return {message: 'skipped'};
126→        }
127→
128→        if(journalKey){
129→            inFlightBookmarkIdsRef.current.add(journalKey);
130→        }
131→
132→        try {
133→            return await mutation.mutateAsync(variables, options);
134→        } finally {
135→            if(journalKey){
136→                inFlightBookmarkIdsRef.current.delete(journalKey);
137→            }
138→        }
139→    };
140→
141→    return {
142→        ...mutation,
143→        mutate: guardedMutate,
144→        mutateAsync: guardedMutateAsync
145→    };
146→}
