 371→const encodeCanvasGalleryCursor = (offset, sort) => {
 372→    const payload = JSON.stringify({
 373→        offset: offset,
 374→        sort: sort
 375→    });
 376→    return Buffer.from(payload, 'utf8').toString('base64');
 377→};
