 466→export const getProfileMediaService = async(userId, limit = PROFILE_MEDIA_LIMIT_DEFAULT, cursor = null) => {
 467→    if(!userId){
 468→        throw {status: 400, error: 'userId is undefined'};
 469→    }
 470→
 471→    const parsedLimit = Number(limit);
 472→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > PROFILE_MEDIA_LIMIT_MAX){
 473→        throw {status: 400, error: `limit should be an integer between 1 and ${PROFILE_MEDIA_LIMIT_MAX}`};
 474→    }
 475→
 476→    const cursorState = parseMediaCursor(cursor);
 477→    const offsets = {...cursorState.offsets};
 478→    const exhausted = {...cursorState.exhausted};
 479→    const pending = Array.isArray(cursorState.pending) ? [...cursorState.pending] : [];
 480→    const unavailableBuckets = [];
 481→    const maxIterations = 6;
 482→    let iterationCount = 0;
 483→
 484→    while(
 485→        pending.length < parsedLimit &&
 486→        PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]) &&
 487→        iterationCount < maxIterations
 488→    ){
 489→        iterationCount += 1;
 490→        const activeBuckets = PROFILE_MEDIA_BUCKETS.filter((bucket) => !exhausted[bucket]);
 491→        const chunkResults = await Promise.all(
 492→            activeBuckets.map((bucket) => listMediaChunkForBucket(bucket, userId, offsets[bucket] || 0, parsedLimit))
 493→        );
 494→
 495→        chunkResults.forEach((result) => {
 496→            offsets[result.bucket] = result.nextOffset;
 497→            exhausted[result.bucket] = result.exhausted;
 498→
 499→            if(result.error){
 500→                console.error(`supabase storage list error on ${result.bucket}:`, result.error);
 501→                unavailableBuckets.push(result.bucket);
 502→                return;
 503→            }
 504→
 505→            pending.push(...result.items);
 506→        });
 507→
 508→        if(chunkResults.every((result) => result.items.length === 0)){
 509→            break;
 510→        }
 511→    }
 512→
 513→    pending.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
 514→
 515→    const selectedItems = pending.slice(0, parsedLimit);
 516→    const remainingItems = pending.slice(parsedLimit);
 517→    const hydratedSelectedItems = await hydrateMediaItems(selectedItems);
 518→
 519→    // If a URL cannot be created for some selected items, try to fill from remaining items.
 520→    if(hydratedSelectedItems.length < parsedLimit && remainingItems.length > 0){
 521→        const neededItemsCount = parsedLimit - hydratedSelectedItems.length;
 522→        const fallbackCandidates = remainingItems.splice(0, neededItemsCount);
 523→        const hydratedFallbackItems = await hydrateMediaItems(fallbackCandidates);
 524→        hydratedSelectedItems.push(...hydratedFallbackItems);
 525→    }
 526→
 527→    const hasMore = remainingItems.length > 0 || PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]);
 528→    const dedupedUnavailableBuckets = [...new Set(unavailableBuckets)];
 529→
 530→    const nextCursor = hasMore
 531→        ? encodeMediaCursor({
 532→            offsets: offsets,
 533→            exhausted: exhausted,
 534→            pending: remainingItems
 535→        })
 536→        : null;
 537→
 538→    return {
 539→        data: hydratedSelectedItems,
 540→        hasMore: hasMore,
 541→        nextCursor: nextCursor,
 542→        unavailableBuckets: dedupedUnavailableBuckets
 543→    };
 544→}
