 696→export const getMonthlyHottestJournalsService = async(limit, userId) => {
 697→    if(isNaN(limit) || limit < 1 || limit > 10){
 698→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
 699→    }
 700→
 701→    const parsedLimit = parseInt(limit);
 702→    const now = new Date();
 703→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
 704→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
 705→
 706→    const {data: journals, error: journalsError} = await supabase
 707→        .from('journals')
 708→        .select(`
 709→            *,
 710→            users(*),
 711→            like_count: likes(count),
 712→            comment_count: comments(count),
 713→            bookmark_count: bookmarks(count)
 714→        `)
 715→        .eq('privacy', 'public')
 716→        .gte('created_at', monthStartUtc.toISOString())
 717→        .lt('created_at', nextMonthStartUtc.toISOString());
 718→
 719→    if(journalsError){
 720→        console.error('supabase error while fetching monthly hottest journals:', journalsError.message);
 721→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
 722→    }
 723→
 724→    const journalsWithInteractions = await attachUserInteractionFlags(journals || [], userId);
 725→    const scored = journalsWithInteractions.map((journal) => {
 726→        const likes = journal?.like_count?.[0]?.count || 0;
 727→        const comments = journal?.comment_count?.[0]?.count || 0;
 728→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 729→        const views = journal?.views || 0;
 730→        const hotScore = (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 731→
 732→        return {
 733→            ...journal,
 734→            hot_score: hotScore
 735→        };
 736→    });
 737→
 738→    scored.sort((a, b) => {
 739→        const scoreDiff = (b?.hot_score || 0) - (a?.hot_score || 0);
 740→        if(scoreDiff !== 0){
 741→            return scoreDiff;
 742→        }
 743→
 744→        const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 745→        if(dateDiff !== 0){
 746→            return dateDiff;
 747→        }
 748→
 749→        return (b?.id || 0) - (a?.id || 0);
 750→    });
 751→
 752→    return {
 753→        data: scored.slice(0, parsedLimit),
 754→        period: {
 755→            startUtc: monthStartUtc.toISOString(),
 756→            endUtc: nextMonthStartUtc.toISOString(),
 757→            timezone: 'UTC'
 758→        },
 759→        totalCandidates: scored.length
 760→    };
 761→}
