 771→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
 772→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
 773→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
 774→    }
 775→
 776→    const parsedLimit = parseInt(limit);
 777→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
 778→    const isNewest = normalizedSort === 'newest';
 779→    const parsedCursor = parseCanvasGalleryCursor(cursor, isNewest ? 'newest' : 'hottest');
 780→    const cursorOffset = parsedCursor.offset;
 781→
 782→    const baseQuery = supabase
 783→        .from('journals')
 784→        .select(`
 785→            *,
 786→            users(*),
 787→            like_count: likes(count),
 788→            comment_count: comments(count),
 789→            bookmark_count: bookmarks(count)
 790→        `)
 791→        .eq('privacy', 'public')
 792→        .eq('post_type', 'canvas')
 793→        .order('created_at', {ascending: false})
 794→        .order('id', {ascending: false});
 795→
 796→    const {data: journals, error: journalsError} = isNewest
 797→        ? await baseQuery.range(cursorOffset, cursorOffset + parsedLimit)
 798→        : await baseQuery.limit(CANVAS_GALLERY_HOT_FETCH_LIMIT);
 799→
 800→    if(journalsError){
 801→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
 802→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
 803→    }
 804→
 805→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
 806→    const normalizedJournals = enrichedJournals.map((journal) => ({
 807→        ...journal,
 808→        hot_score: scoreJournalHotness(journal)
 809→    }));
 810→
 811→    if(!isNewest){
 812→        normalizedJournals.sort((a, b) => {
 813→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
 814→            if(scoreDiff !== 0){
 815→                return scoreDiff;
 816→            }
 817→
 818→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 819→            if(dateDiff !== 0){
 820→                return dateDiff;
 821→            }
 822→
 823→            return (b?.id || 0) - (a?.id || 0);
 824→        });
 825→    }
 826→
 827→    const paginatedJournals = isNewest
 828→        ? normalizedJournals
 829→        : normalizedJournals.slice(cursorOffset, cursorOffset + parsedLimit + 1);
 830→    const hasMore = paginatedJournals.length > parsedLimit;
 831→    const data = hasMore ? paginatedJournals.slice(0, parsedLimit) : paginatedJournals;
 832→    const nextCursor = hasMore
 833→        ? encodeCanvasGalleryCursor(cursorOffset + data.length, isNewest ? 'newest' : 'hottest')
 834→        : null;
 835→
 836→    return {
 837→        data: data,
 838→        sort: isNewest ? 'newest' : 'hottest',
 839→        totalCandidates: normalizedJournals.length,
 840→        hasMore: hasMore,
 841→        nextCursor: nextCursor
 842→    };
 843→}
